const body = ($('Webhook').first().json.body) || {};
if (!body.project_id) return [{ json: { valid:false, error:'project_id obligatorio' } }];
if (!body.collaborator_id) return [{ json: { valid:false, error:'collaborator_id obligatorio' } }];
if (!body.role) return [{ json: { valid:false, error:'role obligatorio (ej: "calculo estructural")' } }];
if (!body.scope || body.scope.toString().length < 10) return [{ json: { valid:false, error:'scope >= 10 chars obligatorio' } }];
return [{ json: {
  valid:true,
  project_id: body.project_id,
  collaborator_id: body.collaborator_id,
  role: body.role.toString().slice(0,200),
  scope: body.scope.toString().slice(0,3000),
  deliverables: Array.isArray(body.deliverables) ? body.deliverables : [],
  fee_eur: body.fee_eur ? Number(body.fee_eur) : null,
  deadline: body.deadline || null
}}];

