INSERT INTO collab_assignments (project_id, collaborator_id, role, scope, deliverables, fee_eur, deadline, status)
VALUES ($1::uuid, $2::uuid, $3, $4, $5::jsonb, $6::numeric, NULLIF($7,'')::date, 'invited')
RETURNING id, role, status, deadline;

