const inserted = $input.first().json;
const data = $('Load Project + Collab').first().json.data;
const input = $('Validate').first().json;
const delivs = (input.deliverables || []).map(d => '<li>' + (typeof d === 'string' ? d : (d.name || JSON.stringify(d))) + '</li>').join('');

const html = `<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto">
<h2 style="color:#2c3e50">Solicitud de colaboracion en proyecto</h2>
<p>Hola ${data.collab_name},</p>
<p>Te invitamos a colaborar en el proyecto <b>${data.project_name}</b> (${data.location}).</p>
<table style="width:100%;border-collapse:collapse">
  <tr><td style="padding:6px;background:#f3f4f6"><b>Rol</b></td><td style="padding:6px">${input.role}</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Especialidad</b></td><td style="padding:6px">${data.collab_specialty}</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Honorarios</b></td><td style="padding:6px">${input.fee_eur ? input.fee_eur.toLocaleString('es-ES') + ' EUR' : 'a convenir'}</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Deadline</b></td><td style="padding:6px">${input.deadline || 'a convenir'}</td></tr>
</table>
<h3>Alcance</h3>
<p>${input.scope}</p>
${delivs ? '<h3>Entregables</h3><ul>' + delivs + '</ul>' : ''}
<p style="margin-top:24px">Por favor, confirma si aceptas el encargo respondiendo a este email. Una vez aceptado, te enviaremos los datos del proyecto y el plazo definitivo.</p>
<p style="font-size:12px;color:#95a5a6">Assignment ID: ${inserted.id}<br>Damian Martinez — ArquitAI</p>
</div>`;

return [{ json: {
  to_collab: data.collab_email,
  cc_architect: $('Load Architect Email').first().json.value,
  subject: 'Colaboracion en ' + data.project_name + ' — ' + input.role,
  html_body: html,
  assignment_id: inserted.id,
  collab_email: data.collab_email,
  project_name: data.project_name
}}];

